INSERT INTO faq_items (category, question, answer, sort_order, page_slug, is_published) VALUES
('cleaning', '六価クロムは全プランで除去されますか？', 'スタンダード洗浄・土泥除去・洗浄プランには六価クロム除去工程が含まれます。シンプル洗浄は表面汚れのみの除去で、六価クロム除去工程は含まれません。六価クロムが懸念される場合はスタンダード以上のプランをお選びください。', 1, '/services/cleaning', true),
('cleaning', 'カビの程度がわからない場合はどうすればいいですか？', '受領後に当社スタッフが状態を確認し、最適なプランを提案します。不明な場合はスタンダード洗浄で受け付け、確認後に土泥除去への切り替えを提案する場合もあります。', 2, '/services/cleaning', true),
('cleaning', '洗骨後に粉骨も依頼できますか？', '可能です。洗骨・粉骨セットプランをご利用いただくと、各工程をはさんで一括対応できます。個別に依頼するより工数・往復手間が少なくなります。', 3, '/services/cleaning', true),
('cleaning', '複数体の遺骨を一括して依頼できますか？', '法人（霊園・寺院・散骨業者）からの一括委託に対応しています。受領書・処理完了報告書・月次請求書を発行します。', 4, '/services/cleaning', true);
INSERT INTO faq_items (category, question, answer, sort_order, page_slug, is_published) VALUES
('carrying', '料金は何を基準に算出されますか？', '戸塚 IC（自社拠点）からお迎え先までの距離・実走時間・利用路線の道路料をもとに算出します。ゴールデンウィーク・盆 / 年始年末は道路料が高くなる場合があります。事前に無料見積りを発行してから確定します。', 1, '/services/carrying', true),
('carrying', '複数体の骨壺を一度に引き取りできますか？', '可能です。車両に積載できる重量の骨壺であれば追加料金なしで対応します。お墓じまいなどで数十体を一括搬送する実績もございます。超大量の場合は別途見積りを行います。', 2, '/services/carrying', true),
('carrying', '法人（寺院・霊園）からの定期依頼は可能ですか？', '対応しています。月次集荷・月次報告書・月次請求書（インボイス対応）を発行します。小口一本化で専任担当が応対します。', 3, '/services/carrying', true),
('carrying', '搬送後にそのまま粉骨・洗骨を依頼できますか？', '可能です。搬送後にそのまま粉骨・洗骨処理へ移行します。内部移送なので再車両輸送のリスクがありません。', 4, '/services/carrying', true);
INSERT INTO faq_items (category, question, answer, sort_order, page_slug, is_published) VALUES
('takeout', '遺骨を郵送できる法的根拠は何ですか？', '日本郵便（ゆうパック）のみが遺骨を取り扱える法的根拠に対応しています（郵便法・日本郵便の内部規程による）。宅配大手（ヤマト・佐川）は遺骨の受付を行っていません。遺骨.comは日本郵便の公式ルールに準拠した手順書を同封し、適切な梱包で発送していただきます。', 1, '/services/takeout', true),
('takeout', '梱包キットの仕様（何が入っていますか）？', '専用強化段ボール（骨壺サイズに対応した複数種）・気泡緩衝材・クッションペーパー・吸水シート・ガムテープ・印字済み着払い伝票・写真付き梱包マニュアル。お客様がご自身で用意するものは一切ありません。', 2, '/services/takeout', true),
('takeout', '往路・復路の送料は誰が負担しますか？', '往路（お客様→ラボ）は着払いのため、お客様の負担はありません。復路（ラボ→お客様）の返送料のみ地域別の実費をご負担いただきます（粉骨等の基本料金とは別途）。', 3, '/services/takeout', true),
('takeout', '骨壺の中に水が溜まっています。そのまま送っても大丈夫ですか？', 'お墓（カロート）に安置されていた骨壺によく見られる現象です。梱包キットに同封の吸水シートと密封ビニール袋を使って水漏れ対策をする手順をご案内しています。水漏れ状態のまま発送すると他の荷物を汚損する恐れがあります。', 4, '/services/takeout', true),
('takeout', '法人（寺院・霊園）からの複数体まとめ郵送はできますか？', '対応しています。月次で複数件をまとめて郵送いただくスキームも可能です。専用の受領書・月次報告書・インボイス対応請求書を発行します。詳細は法人専用フォームからご連絡ください。', 5, '/services/takeout', true);
INSERT INTO faq_items (category, question, answer, sort_order, page_slug, is_published) VALUES
('washing_powdered', 'セットプランにすると割安ですか？', '個別（洗骨のみ・粉骨のみ）と比較して往復運賃・梱包費が1回分省けます。また工程間の移送時間がないため所要日数も短縮されます。料金は状態・サイズで変動しますが、個別依頼の合計より割安になる場合がほとんどです。', 1, '/services/washing-and-pulverization', true),
('washing_powdered', '洗骨→粉骨の間で状態報告はもらえますか？', 'はい。洗骨フェーズ完了時点で中間報告（写真・状態確認メモ）を送付します。その後、粉骨フェーズに進む前に追加オプションの確認をする場合もあります。', 2, '/services/washing-and-pulverization', true),
('washing_powdered', '六価クロムが検出された場合はどう対応しますか？', 'セットプランには六価クロム除去工程が標準で含まれています。除去を確認前に粉骨工程に進むことはありません。証明書に六価クロム除去の実施確認を記載します。', 3, '/services/washing-and-pulverization', true),
('washing_powdered', '法人（寺院・霊園・葬儀社）から複数体を一括依頼できますか？', '対応しています。月次一括受領・月次報告書・インボイス対応の月次請求書を発行します。受領〜返送まで専任担当が対応。詳細は法人相談フォームからご連絡ください。', 4, '/services/washing-and-pulverization', true),
('washing_powdered', '粉骨証明書は発行できますか？', 'オプション（2,200円）で発行します。管理番号・依頼者氏名・作業日・六価クロム除去実施確認・微粒子規格・担当者名を記載。法人名義での発行にも対応。', 5, '/services/washing-and-pulverization', true);
